mapper.select:
select c.content_id as contentId, c.creator_user_id as creatorUserId, c.pet_id as petId, c.content_type as contentType, c.title as title, c.summary as summary, c.content_text as contentText, c.tags as tags, c.media_url as mediaUrl, c.status as status, c.review_status as reviewStatus, c.review_by as reviewBy, c.review_time as reviewTime, c.review_note as reviewNote, c.create_time as createTime, u.nick_name as creatorName, p.pet_name as petName from biz_content_post c left join sys_user u on u.user_id = c.creator_user_id left join biz_pet_info p on p.pet_id = c.pet_id
and c.status = #{status} and c.creator_user_id = #{creatorUserId} and c.review_status = #{reviewStatus}
order by c.create_time desc
